var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"제프티 바이오테크, 방호 구축 실험지구.\\n<color=#ffd34c>윌버 웨이틀리</color> 대표, 시설 방문 중 ","JPN":"ジェフティ・バイオテック、防護構築実験地区。\\n<color=#ffd34c>ウィルバー・ウェイトリー</color>代表、施設訪問中","ENG":"Jehuty Biotech Defensive Measures Test Zone\\nCEO\xA0<color=#ffd34c>Wilbur Whateley</color> conducting site visit","TWN":"傑夫堤生物科技，防護機制實驗機構。\\n<color=#ffd34c>韋爾伯·韋特利</color>代表親臨設施中 "},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_NULL","text":{"KOREA":"소식은 전해 들었습니다, 대표님. 이렇게 다시 뵙게 되어 영광입니다.","JPN":"お話は聞いております、代表。再びこうしてお会いできて光栄です。","ENG":"I heard the news, sir. It's an honor to meet you again.","TWN":"代表，事情我已經聽說了，很榮幸再次見到您。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L6_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"오랜만이야. 그러고 보니 이 시설 담당자가 자네였지.","JPN":"久しぶりだな。そういえばこの施設の担当者は君だったな。","ENG":"Long time no see. I just remembered you're in charge here.","TWN":"好久不見，這麼說來，這棟設施的負責人是你對吧。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"WILBURLOVER_NPC_NULL_NULL","text":{"KOREA":"자기야, 이 분들은 혹시…….","JPN":"ダーリン、この方たちは……","ENG":"Babe, are these folks…","TWN":"親愛的，他們是……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"아, 너무 무서워하지 마. 겉모습만 이렇지 이 사람들도 다 내 직원들이니까.","JPN":"あまり怖がる必要はないよ。見た目は少し怖いかもしれないけど、みんなうちの社員さ。","ENG":"Oh, there's no need to be so scared. They may look intimidating, but they all work for me.","TWN":"不用怕，他們也都是我的員工，只是長得比較兇狠而已。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_NULL","text":{"KOREA":"그렇습니다. 예전에 잠시 범죄 조직에 몸을 담았을 뿐, 지금은 어엿한 제프티 바이오테크 소속이죠.","JPN":"そのとおりです。以前、しばらく犯罪組織に\\n携わっていただけで、今はれっきとしたジェフティ・バイオテック所属です。","ENG":"That's right. We may have been affiliated with a criminal organization briefly, but we're all legitimate employees of Jehuty Biotech now.","TWN":"是的，雖然以前曾經誤入歧途，但現在是屬於正派公司 傑夫堤生物科技的員工。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_NULL","text":{"KOREA":"시설 담당자로서 방문을 환영합니다, 사모님.","JPN":"施設担当者として訪問を歓迎します、奥様。","ENG":"Please allow me to welcome you as this site's manager, Mrs. Whateley.","TWN":"夫人，我代表設施歡迎您來訪。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"WILBURLOVER_NPC_NULL_NULL","text":{"KOREA":"사, 사모님이라니요……. 결혼, 아직인데…….","JPN":"お、奥様だなんて……結婚は、まだなのに……","ENG":"M-missus…? But we haven't gotten married… yet.","TWN":"夫…什麼夫人啦……我們又還沒結婚……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"하하, 이 친구가 확실히 말재주가 좋아.","JPN":"アハハ、空気も読めてユーモアもある人だな。いいぞ。","ENG":"Haha, this fella sure has a way with words.","TWN":"哈哈～嘴真還真甜。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"리플레이서 신디케이트 시절에는 이제 더 미련 없나?","JPN":"リプレイサー・シンジケート時代にもう未練はないのか？","ENG":"Do you really have no regrets about moving on from the Syndicate days?","TWN":"克隆集團的事你已經都放下了嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_NULL","text":{"KOREA":"그럼요. 킹의 유지를 잇겠다고 설치는 자들은 극히 일부에 불과합니다.","JPN":"もちろんです。キングの遺志を継ぐなどと騒ぐ者は、ごく一部に過ぎません。","ENG":"Of course not. Only a select few remain fanatical enough to continue the legacy of King.","TWN":"當然，吵著說要繼承帝皇遺志的人，只有極少部分而已。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_NULL","text":{"KOREA":"조직이 무너진 이상 저희들도 각자 살 길을 찾아야죠.","JPN":"組織が崩壊した以上、私たちも各自生きる道を探さなければなりません。","ENG":"Now that the organization has disbanded, we've all got to find our own way to make our living.","TWN":"組織解散後，我們也就分道揚鑣了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"흐음. 그 말을 들으니 우리 회사에서 지내기는 어떤지 궁금해지는군.","JPN":"ほう、そう言われるとうちの会社に所属した感想が気になってくるな。","ENG":"Hmm... That reminds me, I'm curious how accommodating you've found this company.","TWN":"嗯，你聽這麼說，反而有點好奇，那在我們公司做事感覺如何？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_NULL","text":{"KOREA":"더할 나위 없이 훌륭합니다.","JPN":"この上なく素晴らしいです。","ENG":"Oh, it couldn't be better.","TWN":"棒到不行。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_NULL","text":{"KOREA":"특히 그로니아 반군들과 제휴해서 실험체를 대량 조달한다는 발상은 무척 흥미롭더군요.","JPN":"特にグロニア反乱軍と提携して、実験体を大量調達するという発想はとても興味深いです。","ENG":"I'm particularly intrigued by the notion of partnering with the Gronia insurgents to secure a mass supply of test subjects.","TWN":"尤其是和格羅尼亞叛軍合作，大量取得實驗體的想法，根本是神來一筆。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"쉬운 협상 상대는 아니었지. 최근에는 대가로 기상 조절기까지 빼돌리게 해 줬으니까.","JPN":"簡単な交渉相手ではなかった。最近は取引の対価として気象調節機まで横流ししてやったからな。","ENG":"They drove a hard bargain. Recently, I've even had to let them pilfer a weather controller.","TWN":"他們可不好應付呢，最近才幫他們弄到氣象調節器而已。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"시설의 보안 수준은 어떻지?","JPN":"施設のセキュリティレベルはどうだ？","ENG":"How's the security around here?","TWN":"設施的安全等級如何？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_NULL","text":{"KOREA":"안심하십시오. 그로니아의 실험지구를 잃은 뒤로 각별히 신경 써 뒀습니다.","JPN":"ご安心ください。グロニアの実験地区を失ってから、格別に気を使って体制を整えておきました。","ENG":"There's not a thing to worry about. We've taken extra care after the loss of the Gronian experimental district.","TWN":"您放心吧，自從失去格羅尼亞的實驗區後，我們就格外注意。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_NULL","text":{"KOREA":"특히 지금 계신 이 방공호까지 도달하려면 1,000여 개의 격벽들부터 돌파해야 합니다.","JPN":"特に、今いらっしゃる防空壕まで到達するには、1,000個余りの隔壁を突破しなければなりません。","ENG":"Any intruder will have to go through a thousand walls to get to this bunker.","TWN":"特別是您現在所在的防空洞，要抵達這裡起碼要突破1,000多道牆。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_NULL","text":{"KOREA":"이터니움 함량을 높인 합금을 사용해 최근 실전 배치된 벙커버스터에도 완벽한 방호력을 자랑하죠.","JPN":"エタニウム含量を高めた合金を使用し、最近実戦配備されたバンカーバスターも完璧な防護力を誇ります。","ENG":"We used an alloy rich with Eternium to withstand the impact from the newest bunker buster bombs.","TWN":"使用永恆之金含量高的合金後，最近實戰配置的掩體炸彈也發揮完美的保護力。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"훌륭한 덫이군. 잘하면 경호실장이 오기 전에 그 지긋지긋한 걸 처리해 버릴 수도 있겠어.","JPN":"立派な罠だな。うまくいけば警護室長が着く前にあのうんざりするやつを始末できるかもしれない。","ENG":"A most outstanding trap. If we're lucky, I might be able to be rid of that tiresome wretch before my head of security gets here.","TWN":"做得非常好，這樣說不定在護衛室長抵達前，就可以先處理掉那個討債鬼。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_NULL","text":{"KOREA":"물론입니다. 누구든 여기 들어오는 순간 발이 묶인 채 사냥감으로 전락하겠죠.","JPN":"もちろんです。どんな者でもここに入ってきた瞬間足止めされ、ただの獲物と化すでしょう。","ENG":"Of course. Once they set foot here, it'll be like shooting fish in a barrel.","TWN":"沒問題，任何人只要踏入這裡就會瞬間成為囊中物。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_NULL","text":{"KOREA":"무슨 일이지, 시스템?","JPN":"何事だ、システム？","ENG":"What is it, System?","TWN":"系統，發生什麼事？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"AUTO_OPR_NULL_NULL","text":{"KOREA":"시설 내부에 침입자가 감지되었습니다. 현재 보안 요원들이 대응 중입니다.","JPN":"施設内部に侵入者が感知されました。現在セキュリティ担当が対応中です。","ENG":"Intruder detected within the compound. Security agents are currently responding.","TWN":"感應到有外人入侵設施內部，安全人員正在處理中。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AUTO_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L40_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"보나마나 호라이즌이겠지. 무식하다는 건 참 딱하군.","JPN":"どうせホライズンだろう。無知ってことは実に哀れなことだ。","ENG":"I bet it's Horizon. I almost pity the fool for being such a brute.","TWN":"不用想也知道是地平線，真的是地獄無門你偏闖。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"AUTO_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"AUTO_OPR_NULL_NULL","text":{"KOREA":"19.","JPN":"19。","ENG":"19.","TWN":"19"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"AUTO_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"호텔에서 날 봤을 때 바로 잡았어야지. 호라이즌.","JPN":"ホテルで僕に会った時にすぐ殺すべきだったな、ホライズン。","ENG":"You should have taken me right when you spotted me at the hotel, Horizon.","TWN":"地平線，誰叫你沒在飯店時就把我處理掉。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AUTO_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"AUTO_OPR_NULL_NULL","text":{"KOREA":"42.","JPN":"42。","ENG":"42.","TWN":"42"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AUTO_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"제 발로 죽을 곳에 기어 들어오다니…….","JPN":"自らの足で墓場に来るとは……","ENG":"Now you've crawled into your own death trap…","TWN":"居然自己送上門來找死……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"AUTO_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"AUTO_OPR_NULL_NULL","text":{"KOREA":"79.","JPN":"79。","ENG":"79.","TWN":"79"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"AUTO_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"음? 시스템이 왜 저러지? 오류가 생긴 거 아닌가?","JPN":"うん？　システムがどうかしたのか？　エラーか？","ENG":"Huh? What's wrong with the System? Some kind of an error?","TWN":"嗯？系統怎麼回事？是壞掉了嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"AUTO_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_NULL","text":{"KOREA":"그, 그럴 리가 없습니다. 구식이긴 하지만 그만큼 신뢰성이 높으니까요.","JPN":"そ、そんなはずがありません。旧式ではありますが、それだけ信頼性が高いですから。","ENG":"I-it can't be. It may be an older model, but it's that much more reliable.","TWN":"這…怎麼可能，雖然是舊型的，但可信度很高。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"AUTO_OPR_NULL_NULL","text":{"KOREA":"110.","JPN":"110。","ENG":"110.","TWN":"110"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_NULL","text":{"KOREA":"크흠! 시스템, 지금 뭘 보고하는 건가?","JPN":"システム、今報告している数字はなんだ？","ENG":"Ahem! System! What exactly are these numbers you're reporting?","TWN":"咳咳！系統，這些數字是什麼意思？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"AUTO_OPR_NULL_NULL","text":{"KOREA":"침입자가 돌파한 격벽 수입니다. 사용자님.","JPN":"侵入者が突破した隔壁数です、管理者様。","ENG":"They're the number of walls the intruder has breached, dear user.","TWN":"是侵入者突破的關卡數量，使用者。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AUTO_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"AUTO_OPR_NULL_NULL","text":{"KOREA":"파손 상태 갱신이 지연되고 있으니 실제 수량과 오차가 발생해도 양해 부탁드립니다.","JPN":"破損状態の更新が遅れているため、実際の数量と誤差が生じていること、ご了承ください。","ENG":"There may be a slight discrepancy between the actual number due to a delay in damage assessment. Thank you for your understanding.","TWN":"由於毀損狀態無法即時更新，數量可能會有誤差，敬請見諒。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AUTO_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_NULL","text":{"KOREA":"…………뭐?","JPN":"……何だと？","ENG":"…What?","TWN":"………什麼？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_HATE"},"C":null,"R":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"감시 카메라! 그 사채꾼이 있는 곳을 비춰라! 어서!","JPN":"監視カメラを！　あの闇金業者の居場所を映せ！　はやく！","ENG":"Security camera! Give us a visual on the loan shark! Now!","TWN":"監視器！給我拍那個高利貸現在的位置！快！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"MOB_HORIZON_NULL_NULL","text":{"KOREA":"틀렸어! 너무 빨라서 조준할 수가 없습니다!","JPN":"できません！　敵が速すぎて照準できません！","ENG":"It's no use! The target's too fast to aim at!","TWN":"可惡！根本快到無法瞄準！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOB_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MBOSS_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"MBOSS_HORIZON_NULL_NULL","text":{"KOREA":"비상사태다! 격벽을 내리고 황산 가스 투입해!","JPN":"非常事態だ！　隔壁を降ろして硫酸ガスを投入しろ！","ENG":"It's an emergency! Activate the walls and release the sulfuric acid gas!","TWN":"緊急狀態！放棄那些牆，換用硫磺瓦斯！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOB_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MBOSS_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>301번 격벽 파손. 유출 우려로 투입이 불가능합니다.</color>","JPN":"<color=#ff3636>301番隔壁破損。流出の恐れがあるため投入できません。</color>","ENG":"<color=#ff3636>Wall 301 damaged. Cannot release gas due to leakage concerns.</color>","TWN":"<color=#ff3636>301號牆毀損，有外洩危險，無法使用硫磺瓦斯。</color>"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>302번 격벽 파손. 303번 격벽 파손. 304, 305, 306번 격벽 파손.</color>","JPN":"<color=#ff3636>302番隔壁破損。303番隔壁破損。304、305、306番隔壁破損。</color>","ENG":"<color=#ff3636>Wall 302 damaged. Wall 303 damaged. Walls 304, 305, 306 damaged.</color>","TWN":"<color=#ff3636>302號牆毀損。303號牆毀損。304、305、306號牆毀損。</color>"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MOB_HORIZON_NULL_NULL","text":{"KOREA":"쏴! 어떻게든 멈춰야 한다!","JPN":"撃て！　何としても止めろ！","ENG":"Just shoot! We have to stop her, no matter what!","TWN":"開槍！不管怎樣一定要擋下她！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOB_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MBOSS_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"MBOSS_HORIZON_NULL_NULL","text":{"KOREA":"격벽을 그냥 맨몸으로 부수고 가 버리는데 세울 틈이 어디 있습니까!?","JPN":"隔壁を生身で壊して行っているんです！　止める隙もありません！","ENG":"But how can we stop her when she's literally just running through those walls?","TWN":"她動作快到根本看不到車尾燈，請問要怎麼瞄準？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOB_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MBOSS_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"감시장치를 통해 지켜보고 있겠죠. 윌버.","JPN":"監視装置を通じて見ているでしょう、ウィルバー。","ENG":"I'm sure you're watching me through the surveillance system, Wilbur.","TWN":"韋爾伯，你正在監視器前看著對吧？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"지금 가고 있습니다. 도착하기 전까지 납부할 금액을 준비해 두십시오.","JPN":"今向かっています。到着するまで納付する金額を用意しておいてください。","ENG":"I'm on my way. I suggest you prepare the funds prior to my arrival.","TWN":"我正在去找你的路上，在我抵達前，請先將該繳的錢準備妥當。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"추가로 문짝들이 허름하더군요. 교체를 추천드립니다.","JPN":"あと、扉がかなり粗末なものでした。買い替えをおすすめします。","ENG":"On another note, your doors are rather flimsy. I recommend you have them replaced.","TWN":"另外，這些門有點不堪一擊，我勸你還是換一批吧。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_NULL","text":{"KOREA":"마, 말도 안 돼……! 계산대로라면 프로그레시브 타입도 파괴하는 데 시간이 걸릴 텐데……!","JPN":"あ、あり得ない……！　計算どおりだとプログレッシブタイプも破壊に時間がかかるはずなのに……！","ENG":"T-that's impossible…! By my calculation, it should significantly slow down even a Progressive Type!","TWN":"這…怎麼可能…！這都是經過計算的，就算是可操控類型，也要好幾個小時才能突破才對……！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_NULL","text":{"KOREA":"뭔가 잘못됐어! 저런 햇병아리 같은 계집애가 맨몸으로 부술 수 있을 리가!!","JPN":"何かがおかしい！　あんなガキが生身で壊せるものではない！！","ENG":"Something's wrong! That little twig of a girl couldn't possibly smash through these walls!","TWN":"一定是哪裡有問題！那種乳臭未乾的丫頭，怎麼可能赤手空拳就擊碎牆！！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"사령관. 긴 말 할 필요 없다.","JPN":"司令官、ごちゃごちゃ言わないでいい。","ENG":"Commander. You can save your breath.","TWN":"司令官，說這麼多幹嘛。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"타격조가 맥을 못 출 때부터 이 정도 저항은 예상하고 있었어.","JPN":"突撃隊がされるがままだった時から、この程度の抵抗は予想していた。","ENG":"I already expected this much resistance when I saw how much the strike squad struggled.","TWN":"這種情況我早就預料到，畢竟打擊組那麼不堪一擊。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"실험체를 투입해. 저 녀석한테 우리 회사 기술이 얼마나 우수한지 보여 줘야지.","JPN":"実験体を投入しろ。あいつに我が社の技術がどれほど優れたものなのかを見せてやろう。","ENG":"Release the test subject. It's time we showed that little brat how superior our technology is.","TWN":"派出實驗體！讓那丫頭知道我們公司的技術有多厲害！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_NULL","text":{"KOREA":"실험체라면…… 아직 조정이 끝나지 않아 다소 난폭할 수 있습니다.","JPN":"実験体なら……まだ調整が終わっていないので、多少凶暴な可能性があります。","ENG":"But the test subject may be rather aggressive, as we're not quite done with the calibrations yet.","TWN":"實驗體嗎……因為還沒完全調整好，可能會有點不受控。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"더 좋지. 저 사채꾼 낯짝이 겁에 질려 일그러지는 걸 보고 싶거든.","JPN":"好都合だ。あの闇金業者の顔が恐怖で歪むのを見たいんだ。","ENG":"All the better. Nothing would make me happier than seeing that loan shark tremble in fear.","TWN":"那更好，最好是讓那丫頭嚇到臉歪！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_NULL","text":{"KOREA":"……알겠습니다. 대표님.","JPN":"……承知しました、代表。","ENG":"…Very well, boss.","TWN":"……是，代表！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_NULL","text":{"KOREA":"시스템, 실험체의 격리를 해제한다! 관리 인원들은 전원 대피시켜라!","JPN":"システム、実験体の隔離を解除する！　管理人は全員避難させろ！","ENG":"System, release the test subject from quarantine! Evacuate all the staff!","TWN":"系統，實驗體解除隔離！管理人員全員疏散！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"AUTO_OPR_NULL_NULL","text":{"KOREA":"성문 인식 완료. 실험체의 실전 영상을 기록합니다.","JPN":"声紋認識完了。実験体の実戦映像を記録します。","ENG":"Voice command acknowledged. Commencing video recording of the test subject's combat trial.","TWN":"聲音辨識完畢，紀錄實驗體實戰影片。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AUTO_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L43_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>989번 격벽 파손. 기밀 지정된 연구 자료 소각을 준비합니다.</color>","JPN":"<color=#ff3636>989番隔壁破損。機密指定の研究資料の焼却を準備します。</color>","ENG":"<color=#ff3636>Wall 989 damaged. Preparing destruction of classified research data.</color>","TWN":"<color=#ff3636>989號牆毀損。準備燒毀機密研究資料。</color>"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"침식파 감지. 파형 분석 결과 대형 개체로 추정됩니다.","JPN":"侵食波感知。波形分析の結果、大型個体と推定されます。","ENG":"Corruption Ray detected. Analysis suggests the source is a large specimen.","TWN":"感應到侵蝕波，分析結果推測為大型個體。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"침식체들과 교류가 잦아졌군요, 윌버. 사냥감 취급도 안 해 줘서입니까.","JPN":"侵食体との交流が頻繁になったようですね、ウィルバー。獲物扱いすらしてもらえないからですか。","ENG":"I see you've been interacting extensively with Corrupted Objects, Wilbur. Perhaps they've realized you'll make a foul morsel.","TWN":"韋爾伯，沒想到你還和侵蝕體打交道。是因為他們根本不把你當成獵物嗎？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"흥. 멋대로 지껄여 보시지, 고철 사채꾼.","JPN":"ふん。勝手にほざいてろ、鉄くずの闇金野郎。","ENG":"Hmph. Babble all you want, you piece of junk loan shark.","TWN":"哼，你就盡量嘴砲吧，廢鐵高利貸！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L48_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"하지만 이 녀석 앞에서는 그렇게 버릇없이 못 굴 거다.","JPN":"こいつを相手にその余裕がいつまで続くか楽しみだな。","ENG":"Let's see if you'll still be so cocky in front of this thing.","TWN":"我看你在這傢伙面前還能囂張多久！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ABOMINATION_REPLACER_NULL_NULL","text":{"KOREA":"크어어어어어어어!","JPN":"グオオオオオオオ！","ENG":"Grrroar!!!","TWN":"吼喔喔喔喔喔！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABOMINATION_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MONSTER_MOVEMENT_11"},{"id":"L3_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"리플레이서 신디케이트가 제작했다던 괴물이군요.","JPN":"リプレイサー・シンジケートが作ったという化け物ですね。","ENG":"This must be the monster fabricated by the Replacer Syndicate.","TWN":"原來是克隆集團製作的怪物。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"그래. 생체조직 구조는 아직 불완전하지만 위력만큼은 원본 이상이다.","JPN":"ああ。生体組織の構造はまだ不完全だが、威力だけはオリジナル以上だ。","ENG":"That's right. Although it remains anatomically incomplete, its power already exceeds that of the original.","TWN":"沒錯，雖然生物組織結構還不完整，但威力可是比原本的更厲害！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"리플레이서 신디케이트와 연관되었다면, 마젤란 예언회의 잔당들과도 손을 잡은 겁니까.","JPN":"リプレイサー・シンジケートと関連しているなら、マジェラン預言会の残党とも手を組んだのですか。","ENG":"If you are associated with the Syndicate, have you also partnered with the remnants of MPS?","TWN":"和克隆集團有關的話，那你也有勾結麥哲倫預言會的餘黨嗎？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L6_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"아, 그 버러지들 말이지.","JPN":"ああ、あの人間のクズ集団か。","ENG":"Oh, you mean those losers?","TWN":"喔～你說那些蟲子喔？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"조금은 기대를 걸고 투자했지만 실패했다면 그걸로 끝이지.","JPN":"少しは期待して投資したが、失敗したならそれで終わる関係だ。","ENG":"Admittedly, I might have overestimated them with my investment, but that's the end of it.","TWN":"我投資他們時本來是有點期待的，失敗的話就不再合作就好。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"어차피 나도, 내 회사도 그 정도는 가벼운 손실에 불과하거든.","JPN":"どうせ僕も、僕の会社も、その程度は軽い損失に過ぎないからな。","ENG":"A loss like that is merely peanuts for me and this company.","TWN":"反正那點小錢我或是我公司也不是賠不起。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"이제 감이 오나, 호라이즌?","JPN":"もうわかったか、ホライズン？","ENG":"Now do you see, Horizon?","TWN":"怎麼樣，地平線？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_PRIDE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"난 이제 너 따위가 감히 말도 못 붙일 몸이야. 사는 세상이 다르다는 거다.","JPN":"僕はもう貴様ごときが気安く話せる立場ではない。生きる世界が違うということだ。","ENG":"I'm way beyond your league now. The world has changed.","TWN":"我現在可不是你隨隨便便就能碰的，我跟你是兩個不同世界的人。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"당신이 자랑하는 알량한 사회적 지위는 제 고려 대상에 포함되지 않습니다.","JPN":"あなたが誇る社会的地位は私の考慮対象に含まれません。","ENG":"Your petty social status that you boast so eagerly is not part of my calculus.","TWN":"你驕傲的社會地位，不在我的考慮範圍內。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"제가 당신을 판단하는 기준은 당신이 채무자인지, 아닌지뿐입니다.","JPN":"私があなたを判断する基準は、あなたが債務者かどうかだけです。","ENG":"I assess you strictly based on whether you owe me money or not.","TWN":"我判斷你的標準只有，是或不是債務人而已。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"그러니 얌전히 빚을 갚으시죠, 윌버.","JPN":"だから大人しく借金を返してください、ウィルバー。","ENG":"So I suggest you comply and repay your debt, Wilbur.","TWN":"所以韋爾伯，還是乖乖還債吧。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"변제를 계속 피하려고 하면 추심 중 부수적인 손실로 더 많은 것을 잃게 될 겁니다.","JPN":"このまま返済から逃れようとするなら、取り立て中の付随的な損失でより多くのものを失うことになるだけです。","ENG":"If you continue to dodge the collection, you will lose far more from the ensuing collateral damage.","TWN":"若是再找藉口不還債，恐怕你會遭遇更多損失。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"하하! 아직도 그딴 소리를 지껄일 여유가 있나 본데, 그 실험체는……!","JPN":"ハハ！　まだそんなことをほざく余裕があるみたいだが、その実験体は……！","ENG":"Haha! You still got the nerve to ramble about that? But that test subject is...","TWN":"哈哈！死到臨頭還嘴硬，那個實驗體……！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"ABOMINATION_REPLACER_NULL_NULL","text":{"KOREA":"크어어어어어억!!","JPN":"グオオオオオオオッ！！","ENG":"Groooar!!","TWN":"吼喔喔喔喔喔！！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABOMINATION_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"왜 말을 도중에 끊습니까. 계속 떠들고 계시죠.","JPN":"聞いています。話を続けてください。","ENG":"Your were saying? Please continue your yapping.","TWN":"為何話說一半？怎麼不繼續？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L27_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"………….","JPN":"…………","ENG":"………….","TWN":"…………"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_NULL","text":{"KOREA":"대, 대표님……? 보이십니까……?","JPN":"だ、代表……？　見えていますか？","ENG":"B-boss…? Do you see what I see?","TWN":"代…代表…？你有看到嗎……？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_NULL","text":{"KOREA":"어보미네이션이 적의 공격에 괴로워하는 것 같은데…….","JPN":"アボミネーションが敵の攻撃に苦しんでいるような……","ENG":"It seems the Abomination is actually in pain from the enemy's attacks…","TWN":"憎惡好像處於劣勢……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"뭐, 뭐냐. 그 쇠파이프는.","JPN":"な、なんだ？　その鉄パイプは……","ENG":"W-what the… What's with the pipe?","TWN":"搞什麼，那個鐵管！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"설마…… 이면세계에서 희귀한 아티팩트라도 찾은 거냐?","JPN":"まさか……裏世界から希少なアーティファクトでも見つけたのか？","ENG":"Could it be… you found a rare artifact in the Counterside?","TWN":"難道……是她在異界找到的稀有人造神器嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"부정. 레이첼의 배관 수리 아르바이트에 끌려갔을 때 뜯어 온 쇠파이프입니다.","JPN":"否定。レイチェルの配管修理アルバイトに付き合わされた時に取ってきた鉄パイプです。","ENG":"Negative. It's merely a metal pipe I tore off when Rachel dragged me to her plumbing gig.","TWN":"答錯，這就只是和瑞秋去打工修理管線時，順手拆下來的鐵管而已。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"30년 넘게 자신의 사명에 충실했던 역전의 용사라고 할 수 있죠.","JPN":"30年も自分の使命に忠実だった歴戦の勇者とも言えます。","ENG":"It is a resilient weapon that served its calling faithfully for over 30 years.","TWN":"這根鐵管30年來盡忠職守，說是它是個勇士都不為過。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"집주인도 어차피 버릴 쓰레기니까 알아서 하라고 선물로 주더군요.","JPN":"大家さんもどうせ捨てるゴミだから勝手にしろとプレゼントしてくれました。","ENG":"The homeowner gave it to me as a gift, since they were going to throw it out anyway.","TWN":"那個家的主人反正也要當垃圾丟掉，就送給我當禮物。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"개소리 지껄이지 마!","JPN":"ふざけるな！","ENG":"Cut the crap!","TWN":"少在那胡說八道！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_HATE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"평범한 쇠파이프라고! 그걸로 쳤더니 내 실험체가 고통스러워한다고?!","JPN":"普通の鉄パイプだと？　それに打たれた実験体が苦しんでいるだと！？","ENG":"Just an ordinary metal pipe?! You mean to say something like that can inflict pain on my test subject?","TWN":"什麼管線的鐵管！用那種鐵管就可以打得我的實驗體哀哀叫？！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"지금 누굴 바보로 아는 거냐?! 이 개망나니 계집애야!","JPN":"バカにするな！！　このアバズレが！","ENG":"Do you take me for a fool?! You insolent little wretch!","TWN":"你把當我白癡嗎？！可惡的臭丫頭！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"노안이라도 왔나 보군요, 윌버. 척 보기에도 물렁물렁하게 생기지 않았습니까.","JPN":"老眼が進んだのですか、ウィルバー。ぱっと見ても、もろそうな見た目ですが。","ENG":"Your eyesight must be growing poor in your old age, Wilbur. Can't you tell at a glance how vulnerable this creature is?","TWN":"韋爾伯，看來你還有老花眼。看也知道這只是條普通的破鐵管吧？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"조용히 그곳에서 기다리고 계십시오. 금방 찾아가겠습니다.","JPN":"大人しくそこで待っていてください。すぐ伺います。","ENG":"Stay put quietly over there. I'll be with you shortly.","TWN":"請你安靜在那等候，我很快就會找到你。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"}]`);export{e as default};